public boolean hasPairSum(int[] measurements, int target) {
    for (int i = 0; i < measurements.length; i++) {
        for (int j = i + 1; j < measurements.length; j++) {
            if (measurements[i] + measurements[j] == target) return true;
        }
    }
    return false;
}

def find_duplicates(eventLog):
    duplicates = []
    for i in range(len(eventLog)):
        for j in range(i + 1, len(eventLog)):
            if eventLog[i] == eventLog[j] and eventLog[i] not in duplicates:
                duplicates.append(eventLog[i])
    return duplicates
